INSERT INTO `conversations` (`id`, `question`, `reponse`, `session_id`, `timestamp`, `user_id`) VALUES
	(1, 'Période romaine', '🏛️ <strong>Périodes historiques :</strong><br><br>🏛️ <strong>Punique</strong> (4 monnaie(s))<br>⚔️ <strong>Romaine</strong> (6 monnaie(s))<br>⚔️ <strong>Numide/Romaine</strong> (1 monnaie(s))<br>✝️ <strong>Byzantine</strong> (2 monnaie(s))<br>☪️ <strong>Islamique - Aghlabide</strong> (2 monnaie(s))<br>☪️ <strong>Islamique - Fatimide</strong> (1 monnaie(s))<br>☪️ <strong>Islamique - Hafside</strong> (2 monnaie(s))<br>🗺️ <strong>Numide</strong> (2 monnaie(s))<br>', 'session_1775208843638_w7hdgnyli', '2026-04-03 10:34:09.374610', 3),
	(2, 'Dinars islamiques', '☪️ <strong>Monnaies de la période Islamique</strong> (5) :<br><br>🪙 <strong>Dinar Aghlabide d\'Or</strong><br>&nbsp;&nbsp;📅 850 ap. J.-C. | ⚗️ Or | 📍 Kairouan<br><br>🪙 <strong>Dirham Aghlabide d\'Argent</strong><br>&nbsp;&nbsp;📅 820 ap. J.-C. | ⚗️ Argent | 📍 Kairouan<br><br>🪙 <strong>Dinar Fatimide</strong><br>&nbsp;&nbsp;📅 920 ap. J.-C. | ⚗️ Or | 📍 Al-Mahdiyya<br><br>🪙 <strong>Demi-Dirham Hafside</strong><br>&nbsp;&nbsp;📅 1350 ap. J.-C. | ⚗️ Argent | 📍 Tunis<br><br>🪙 <strong>Kharouba de Tunis</strong><br>&nbsp;&nbsp;📅 1400 ap. J.-C. | ⚗️ Cuivre | 📍 Tunis<br><br>', 'session_1775208907165_5zkj68cnl', '2026-04-03 10:35:09.721543', 6),
	(3, 'Période romaine', '🔍 <strong>Monnaies correspondantes :</strong><br><br>🪙 <strong>Denier Romain</strong><br>&nbsp;&nbsp;🏛️ Romaine | ⚗️ Cuivre | 📍 Africa Proconsularis | 📅 402 ap. J.-C.<br>&nbsp;&nbsp;📝 Monnaie romaine frappee en Afrique Proconsulaire....<br><br>🪙 <strong>Denier Romain</strong><br>&nbsp;&nbsp;🏛️ Romaine | ⚗️ Cuivre | 📍 Africa Proconsularis | 📅 84 av. J.-C.<br>&nbsp;&nbsp;📝 Monnaie romaine frappee en Afrique Proconsulaire....<br><br>🪙 <strong>Denier Romain</strong><br>&nbsp;&nbsp;🏛️ Romaine | ⚗️ Cuivre | 📍 El Djem (Thysdrus) | 📅 303 ap. J.-C.<br>&nbsp;&nbsp;📝 Monnaie romaine frappee en Afrique Proconsulaire....<br><br>🪙 <strong>Denier Romain</strong><br>&nbsp;&nbsp;🏛️ Romaine | ⚗️ Cuivre | 📍 Hadrumetum (Sousse) | 📅 133 ap. J.-C.<br>&nbsp;&nbsp;📝 Monnaie romaine frappee en Afrique Proconsulaire....<br><br>🪙 <strong>Denier Romain</strong><br>&nbsp;&nbsp;🏛️ Romaine | ⚗️ Cuivre | 📍 Africa Proconsularis | 📅 304 ap. J.-C.<br>&nbsp;&nbsp;📝 Monnaie romaine frappee en Afrique Proconsulaire....<br><br>', 'session_1776894021477_p18x89qxo', '2026-04-22 22:41:03.997349', 5),
	(4, 'combien du monnaie romaine', 'Bonjour Salah ! 🤔\n\nEn regardant les informations fournies, nous pouvons identifier plusieurs monnaies romaines frappées en Afrique Proconsulaire :\n\n* 303 : Denier Romain avec portrait d\'Hadrien et l\'Afrique personnifiée tenant des épis.\n* 400 : Denier Romain avec buste de Septime Severe et Neptune tenant un trident.\n* -84 : Denier Romain avec buste de Septime Severe et Carthago debout.\n* 304 : Denier Romain avec buste de Septime Severe et La Victoire ailee.\n\nCes monnaies romaines frappées en Afrique Proconsulaire sont toutes des deniers, qui étaient des pièces de monnaie utilisées pour les transactions commerciales et financières. 📈\n\nEn résumé, il y a 4 monnaies romaines frappées en Afrique Pro', 'session_1776894021477_p18x89qxo', '2026-04-22 22:42:18.810113', 5),
	(5, 'en tunisie combien du monnaies punique', '🏛️ La collection MONETA contient <strong>100 monnaies</strong> de la période <strong>Punique</strong>.<br><br>Exemples :<br>🪙 <strong>Shekel Punique</strong> — ⚗️ Electrum | 📍 Byzacene | 📅 344 av. J.-C.<br>🪙 <strong>Demi-Shekel</strong> — ⚗️ Or | 📍 Zeugitana | 📅 200 av. J.-C.<br>🪙 <strong>Bronze Punique</strong> — ⚗️ Argent | 📍 Zeugitana | 📅 352 av. J.-C.<br>🪙 <strong>Demi-Shekel</strong> — ⚗️ Or | 📍 Zeugitana | 📅 154 av. J.-C.<br>🪙 <strong>Statere de Carthage</strong> — ⚗️ Or | 📍 Byzacene | 📅 277 av. J.-C.<br>', 'session_1776894021477_p18x89qxo', '2026-04-22 22:44:24.890784', 5);
